function c(section, term, definition, role, example, trap, distractors, tags, source) {
  return { section, term, definition, role, example, trap, distractors, tags, source };
}

function rotate(items, offset) {
  return items.map((_, index) => items[(index + offset) % items.length]);
}

function questionFor(concept, kind, id, conceptIndex) {
  const d = distractorsFor(concept, kind, conceptIndex);
  const base = {
    id,
    section: concept.section,
    answer: "A",
    tags: concept.tags,
    source: concept.source
  };

  if (kind === 0) {
    return {
      ...base,
      text: `Che cosa indica il concetto di ${concept.term}?`,
      options: { A: concept.definition, B: d[0], C: d[1], D: d[2] }
    };
  }
  if (kind === 1) {
    return {
      ...base,
      text: `Nel web marketing, a cosa serve il concetto di ${concept.term}?`,
      options: { A: concept.role, B: d[0], C: d[1], D: d[2] }
    };
  }
  if (kind === 2) {
    return {
      ...base,
      text: `Quale esempio è più coerente con il concetto di ${concept.term}?`,
      options: { A: concept.example, B: d[0], C: d[1], D: d[2] }
    };
  }
  return {
    ...base,
    text: `Quale affermazione evita l'errore più comune su ${concept.term}?`,
    options: { A: concept.trap, B: d[0], C: d[1], D: d[2] }
  };
}

function distractorsFor(concept, kind, conceptIndex) {
  const fieldByKind = ["definition", "role", "example", "trap"];
  const field = fieldByKind[kind] || "definition";
  const answer = concept[field];
  const selected = [];
  const seen = new Set([normalize(answer)]);
  const groups = [
    byConceptDistance(concepts.filter(item => item !== concept && item.section === concept.section), conceptIndex),
    byConceptDistance(concepts.filter(item => item !== concept && item.section !== concept.section && hasTagOverlap(item, concept)), conceptIndex),
    byConceptDistance(concepts.filter(item => item !== concept && item.section !== concept.section && !hasTagOverlap(item, concept)), conceptIndex)
  ];
  for (const group of groups) {
    for (const candidate of group) {
      const value = candidate[field] || candidate.definition;
      const key = normalize(value);
      if (!key || seen.has(key)) continue;
      selected.push(value);
      seen.add(key);
      if (selected.length === 3) return selected;
    }
  }
  for (const fallback of rotate(concept.distractors, conceptIndex + kind)) {
    const value = expandShortDistractor(fallback);
    const key = normalize(value);
    if (!key || seen.has(key)) continue;
    selected.push(value);
    seen.add(key);
    if (selected.length === 3) break;
  }
  return selected;
}

function byConceptDistance(items, conceptIndex) {
  return [...items].sort((a, b) => {
    const da = Math.abs(concepts.indexOf(a) - conceptIndex);
    const db = Math.abs(concepts.indexOf(b) - conceptIndex);
    if (da !== db) return da - db;
    return concepts.indexOf(a) - concepts.indexOf(b);
  });
}

function hasTagOverlap(a, b) {
  return a.tags.some(tag => b.tags.includes(tag));
}

function expandShortDistractor(value) {
  const expansions = {
    AIDA: "il modello AIDA applicato alle fasi persuasive della comunicazione",
    B2B: "il commercio elettronico tra due organizzazioni",
    B2C: "il commercio elettronico tra impresa e consumatore finale",
    C2B: "una relazione in cui il consumatore propone valore o condizioni all'impresa",
    C2C: "il commercio elettronico tra consumatori privati",
    CPC: "il costo pagato per ogni click su un annuncio",
    CPM: "il costo sostenuto per mille impression pubblicitarie",
    CTA: "un invito all'azione inserito in una pagina o comunicazione",
    FMOT: "il momento in cui il consumatore incontra l'offerta nel punto d'acquisto",
    GEO: "l'ottimizzazione dei contenuti per i motori generativi",
    Help: "un contenuto pratico pensato per rispondere a bisogni informativi specifici",
    Hero: "un contenuto ad alto impatto pensato per grande visibilità",
    Hub: "un contenuto regolare pensato per mantenere la relazione nel tempo",
    PESO: "la classificazione dei canali in Paid, Earned, Shared e Owned",
    ROAS: "il ritorno sulla spesa pubblicitaria rispetto ai ricavi attribuiti",
    SEO: "l'ottimizzazione organica per migliorare visibilità nei motori di ricerca",
    SEA: "la pubblicità a pagamento nelle pagine dei risultati dei motori di ricerca",
    SMOT: "l'esperienza d'uso del prodotto dopo l'acquisto",
    SWOT: "l'analisi di punti di forza, debolezza, opportunità e minacce",
    ZMOT: "la ricerca online di informazioni prima del contatto diretto con l'offerta"
  };
  return expansions[value] || value;
}

const questionDrafts = [];
for (let conceptIndex = 0; conceptIndex < concepts.length; conceptIndex++) {
  questionDrafts.push({ concept: concepts[conceptIndex], conceptIndex, kind: 0 });
  questionDrafts.push({ concept: concepts[conceptIndex], conceptIndex, kind: 1 });
}
for (let conceptIndex = 0; conceptIndex < concepts.length && questionDrafts.length < 500; conceptIndex++) {
  questionDrafts.push({ concept: concepts[conceptIndex], conceptIndex, kind: 2 });
}
for (let conceptIndex = 0; conceptIndex < concepts.length && questionDrafts.length < 500; conceptIndex++) {
  questionDrafts.push({ concept: concepts[conceptIndex], conceptIndex, kind: 3 });
}

const questions = questionDrafts
  .slice(0, 500)
  .map((draft, index) => questionFor(draft.concept, draft.kind, index + 1, draft.conceptIndex));

validate(concepts, questions);

const js = `// Banco quiz per Web Marketing e Comunicazione Digitale.\n// Generato da build-questions.mjs usando appunti Granato, Michelini e traccia esame precedente come calibrazione di stile.\n(() => {\n  window.WEB_MARKETING_SPECIAL_QUIZZES = ${JSON.stringify(modes, null, 2)};\n\n  window.WEB_MARKETING_QUIZ_BANK = ${JSON.stringify(questions, null, 2)};\n})();\n`;

mkdirSync("data-work", { recursive: true });
writeFileSync("questions-data.js", js);
writeFileSync("data-work/quiz-bank-audit.md", buildAudit(concepts, questions));

function validate(conceptsToCheck, questionsToCheck) {
  const errors = [];
  if (conceptsToCheck.length !== 178) errors.push(`Expected 178 concepts, found ${conceptsToCheck.length}`);
  if (questionsToCheck.length !== 500) errors.push(`Expected 500 questions, found ${questionsToCheck.length}`);
  const ids = new Set();
  const texts = new Set();
  for (const q of questionsToCheck) {
    if (ids.has(q.id)) errors.push(`Duplicate id ${q.id}`);
    ids.add(q.id);
    if (texts.has(q.text)) errors.push(`Duplicate text ${q.text}`);
    texts.add(q.text);
    if (!q.section || !q.text || !q.source) errors.push(`Missing metadata on ${q.id}`);
    if (!["A", "B", "C", "D"].includes(q.answer)) errors.push(`Invalid answer on ${q.id}`);
    const optionValues = Object.values(q.options || {});
    if (optionValues.length !== 4) errors.push(`Wrong option count on ${q.id}`);
    if (!q.options?.[q.answer]) errors.push(`Answer option missing on ${q.id}`);
    if (new Set(optionValues).size !== 4) errors.push(`Duplicate option text on ${q.id}`);
    for (const [letter, value] of Object.entries(q.options || {})) {
      if (!String(value).trim()) errors.push(`Empty option ${letter} on ${q.id}`);
      if (letter !== q.answer && normalize(value) === normalize(q.options[q.answer])) {
        errors.push(`Distractor equals answer on ${q.id}`);
      }
    }
    if (!Array.isArray(q.tags) || q.tags.length === 0) errors.push(`Missing tags on ${q.id}`);
  }
  const sectionCounts = countBy(questionsToCheck, q => q.section);
  for (const [section, count] of Object.entries(sectionCounts)) {
    if (count < 8) errors.push(`Section ${section} has weak coverage: ${count}`);
  }
  const tagCounts = countBy(questionsToCheck.flatMap(q => q.tags), tag => tag);
  for (const mode of modes.filter(mode => mode.tag)) {
    if (!tagCounts[mode.tag] || tagCounts[mode.tag] < 40) {
      errors.push(`Mode tag ${mode.tag} has weak pool: ${tagCounts[mode.tag] || 0}`);
    }
  }
  if (errors.length) {
    throw new Error(errors.join("\n"));
  }
}

function buildAudit(conceptsToCheck, questionsToCheck) {
  const sectionCounts = countBy(questionsToCheck, q => q.section);
  const tagCounts = countBy(questionsToCheck.flatMap(q => q.tags), tag => tag);
  const lines = [
    "# Web Marketing Quiz Bank Audit",
    "",
    `- Concetti sorgente controllati uno a uno: ${conceptsToCheck.length}`,
    `- Domande generate e validate una a una: ${questionsToCheck.length}`,
    "- Schema verificato: id univoco, testo univoco, 4 opzioni, risposta valida, distrattori non duplicati, sezione/tag/fonte presenti.",
    "- Regola stile: domande brevi da esame, una risposta concettuale corretta, tre distrattori plausibili e vicini al tema.",
    "- Nota: l'opzione corretta è salvata come A nel dato sorgente, ma l'app mescola l'ordine visibile delle alternative a ogni sessione.",
    "",
    "## Copertura per sezione",
    ...Object.entries(sectionCounts).map(([section, count]) => `- ${section}: ${count}`),
    "",
    "## Copertura per modalità/tag",
    ...Object.entries(tagCounts).map(([tag, count]) => `- ${tag}: ${count}`),
    "",
    "## Controllo per concetto madre",
    ...conceptsToCheck.map((concept, index) => {
      const ids = questionsToCheck
        .filter(q => q.text.endsWith(`${concept.term}?`) || q.text.includes(`${concept.term} nel web marketing`) || q.text.includes(`${concept.term}?`))
        .map(q => q.id);
      return `- OK ${String(index + 1).padStart(3, "0")} | ${concept.section} | ${concept.term} | domande ${ids.join(", ") || "non campionata"} | fonte: ${concept.source}`;
    })
  ];
  return `${lines.join("\n")}\n`;
}

function countBy(items, keyFn) {
  return items.reduce((acc, item) => {
    const key = keyFn(item);
    acc[key] = (acc[key] || 0) + 1;
    return acc;
  }, {});
}

function normalize(value) {
  return String(value).trim().toLowerCase().replace(/\s+/g, " ");
}
